def solve(nums: list[int]) -> bool:
    n = len(nums)
    for p in range(1, n - 2):
        for q in range(p + 1, n - 1):
            valid = True
            # Check first part: 0 to p is strictly increasing
            for i in range(p):
                if nums[i] >= nums[i + 1]:
                    valid = False
                    break
            if not valid:
                continue
            # Check second part: p to q is strictly decreasing
            for i in range(p, q):
                if nums[i] <= nums[i + 1]:
                    valid = False
                    break
            if not valid:
                continue
            # Check third part: q to end is strictly increasing
            for i in range(q, n - 1):
                if nums[i] >= nums[i + 1]:
                    valid = False
                    break
            if valid:
                return True
    return False
